const response = $input.first().json;
const rows = response.list || (Array.isArray(response) ? response : []);

if (rows.length === 0) {
  throw new Error('No active projects found in NocoDB');
}

return rows.map(r => ({
  json: {
    body: {
      project_id: r.project_id,
      niche: r.niche || '',
      city: r.city || '',
      target_url: r.target_url || '',
      niche_cluster: r.niche_cluster || 'commercial_local',
      competitors: typeof r.competitors === 'string'
        ? r.competitors.split(',').map(s => s.trim()).filter(Boolean)
        : (Array.isArray(r.competitors) ? r.competitors : []),
      source: 'cron_monthly'
    }
  }
}));

const input = $input.first().json;
const headers = input.headers || {};
const authHeader = headers.authorization || headers.Authorization || '';
const expectedToken = $env.WORKFLOW_API_KEY || '';

// Dev mode: если токен не настроен, пропускаем проверку
if (expectedToken && authHeader !== `Bearer ${expectedToken}`) {
  // Возвращаем ошибку — Quality Gate перехватит
  return [{ json: {
    ...input,
    _auth_failed: true,
    _auth_error: 'Unauthorized: invalid or missing Bearer token'
  }}];
}

return [{ json: { ...input, _auth_failed: false }}];

const raw = $input.first().json;

// Auth failure check (from webhook path)
if (raw._auth_failed) {
  return [{ json: {
    _abort: true,
    _abort_reason: raw._auth_error,
    _abort_code: 401
  }}];
}

const body = raw.body || raw;
const { niche, city, project_id, target_url, competitors, niche_cluster } = body;

// Strict validation
const errors = [];
if (!niche || typeof niche !== 'string' || niche.trim().length < 2) errors.push('niche обязательно (мин. 2 символа)');
if (!city || typeof city !== 'string') errors.push('city обязательно');
if (!project_id) errors.push('project_id обязательно');

if (errors.length > 0) {
  return [{ json: {
    _abort: true,
    _abort_reason: 'Validation: ' + errors.join('; '),
    _abort_code: 422
  }}];
}

// Sanitize competitors
let competitorsList = [];
if (Array.isArray(competitors) && competitors.length > 0) {
  competitorsList = competitors
    .filter(c => typeof c === 'string' && c.startsWith('http'))
    .slice(0, 5); // max 5 для скорости
}

// Sanitize text inputs (anti prompt injection)
const sanitize = (s) => String(s || '').trim()
  .replace(/[<>{}]/g, '')
  .replace(/ignore\s+(previous|all|above)/gi, '[FILTERED]')
  .substring(0, 200);

// Build semantic embedding query
const embedQuery = [
  sanitize(niche),
  sanitize(city),
  'коммерческие факторы ранжирования',
  'Яндекс Google',
  'цены отзывы гарантии доверие конверсия',
  'SEO 2026'
].join(' ');

// Determine niche cluster
const cluster = niche_cluster || 'commercial_local';

return [{ json: {
  niche: sanitize(niche),
  city: sanitize(city),
  project_id,
  target_url: (target_url || '').trim(),
  competitors: competitorsList,
  has_competitors: competitorsList.length > 0,
  niche_cluster: cluster,
  embed_query: embedQuery,
  started_at: new Date().toISOString(),
  workflow_version: 'v4.0_ultra',
  source: body.source || 'webhook',
  _abort: false
}}];

const prev = $input.first().json;
return [{ json: {
  success: false,
  workflow_version: 'v4.0_ultra',
  error: prev._abort_reason || 'Unknown error',
  http_status: prev._abort_code || 500,
  timestamp: new Date().toISOString()
}}];

const validated = $('Validate Input v2').first().json;

// ── RAG personas ──
let personaResults = [];
try { personaResults = $('RAG seo_personas').first().json.result || []; } catch(e) {}

// ── RAG structures ──
let structResults = [];
try { structResults = $('RAG page_structures').first().json.result || []; } catch(e) {}

// ── Page structures from NocoDB ──
let pages = [];
try {
  const resp = $('Fetch Page Structures').first().json;
  pages = resp.list || (Array.isArray(resp) ? resp : []);
} catch(e) {}

// ── EEAT Score ──
let eeatScore = null;
try {
  const resp = $('Fetch EEAT Score').first().json;
  const rows = resp.list || (Array.isArray(resp) ? resp : []);
  if (rows.length > 0) eeatScore = rows[0];
} catch(e) {}

// ── RAG Quality Gate: фильтруем низко-релевантные результаты ──
const qualityPersonas = personaResults.filter(r => {
  const score = r.score || 0;
  const payload = r.payload || {};
  // Проверяем и score, и niche совпадение
  if (score < 0.70) return false;
  if (payload.niche && validated.niche) {
    const pNiche = String(payload.niche).toLowerCase();
    const vNiche = validated.niche.toLowerCase();
    // Хотя бы частичное совпадение ниши
    if (!pNiche.includes(vNiche.substring(0,4)) && !vNiche.includes(pNiche.substring(0,4))) {
      return score >= 0.85; // Только при очень высоком score
    }
  }
  return true;
});

const qualityStructs = structResults.filter(r => {
  if ((r.score || 0) < 0.70) return false;
  if (r.payload?.type === 'commercial_factors_analysis') return false;
  return true;
});

// ── Build RAG context ──
let personaContext = '';
if (qualityPersonas.length > 0) {
  personaContext = '=== ЦЕЛЕВАЯ АУДИТОРИЯ (RAG, quality-filtered) ===\n\n';
  qualityPersonas.forEach((r, i) => {
    const p = r.payload || {};
    const score = Math.round(r.score * 100);
    personaContext += `Персона ${i+1} (релевантность: ${score}%): `;
    if (p.persona_name) personaContext += p.persona_name + ' | ';
    if (p.pain_points) personaContext += 'Боли: ' + (typeof p.pain_points === 'string' ? p.pain_points : JSON.stringify(p.pain_points).substring(0, 400));
    if (p.buying_triggers) personaContext += ' | Триггеры: ' + String(p.buying_triggers).substring(0, 200);
    personaContext += '\n';
  });
} else {
  personaContext = '(Персоны не найдены в RAG или не прошли quality gate)\n';
}

let structContext = '';
if (qualityStructs.length > 0) {
  structContext = '\n=== РЕЛЕВАНТНЫЕ ПРОЕКТЫ (RAG, quality-filtered) ===\n\n';
  qualityStructs.forEach((r, i) => {
    const p = r.payload || {};
    const score = Math.round(r.score * 100);
    structContext += `Проект ${i+1} (сходство: ${score}%): Ниша: ${p.niche || ''} | Город: ${p.city || ''}\n`;
    if (p.factors_summary) structContext += '  Факторы: ' + String(p.factors_summary).substring(0, 500) + '\n';
  });
}

// ── Pages context ──
let pagesContext = '';
if (pages.length > 0) {
  pagesContext = '\n=== СТРУКТУРЫ СТРАНИЦ ПРОЕКТА ===\n\n';
  pages.forEach((r, i) => {
    pagesContext += `${i+1}. [${(r.page_type||'').toUpperCase()}] ${r.cluster_name||''} | URL: ${r.recommended_url||''} | Блоков: ${r.total_blocks||0}`;
    if (r.has_price_block) pagesContext += ' | ✓ Прайс';
    if (r.has_reviews) pagesContext += ' | ✓ Отзывы';
    if (r.has_contacts) pagesContext += ' | ✓ Контакты';
    pagesContext += '\n';
  });
}

// ── EEAT context ──
let eeatContext = '';
if (eeatScore) {
  eeatContext = `\n=== E-E-A-T SCORE (из workflow #06) ===\n`;
  eeatContext += `Experience: ${eeatScore.experience_score || 'N/A'} | `;
  eeatContext += `Expertise: ${eeatScore.expertise_score || 'N/A'} | `;
  eeatContext += `Authority: ${eeatScore.authority_score || 'N/A'} | `;
  eeatContext += `Trust: ${eeatScore.trust_score || 'N/A'} | `;
  eeatContext += `Overall: ${eeatScore.overall_score || 'N/A'}\n`;
}

return [{ json: {
  ...validated,
  rag_context: personaContext + structContext + eeatContext,
  rag_persona_count: qualityPersonas.length,
  rag_struct_count: qualityStructs.length,
  rag_raw_persona_count: personaResults.length,
  rag_raw_struct_count: structResults.length,
  rag_quality_filtered: (personaResults.length - qualityPersonas.length) + (structResults.length - qualityStructs.length),
  pages: pages,
  pages_count: pages.length,
  pages_context: pagesContext,
  eeat_score: eeatScore,
  eeat_available: !!eeatScore
}}];

const ctx = $input.first().json;
const competitors = ctx.competitors || [];

if (competitors.length === 0) {
  // Нет конкурентов — пропускаем с пустой матрицей
  return [{ json: {
    ...ctx,
    _comp_url: '',
    _comp_skip: true
  }}];
}

// Создаём по одному item на каждого конкурента
// HTTP Request обработает каждый по очереди
return competitors.map((url, i) => ({
  json: {
    ...ctx,
    _comp_url: url,
    _comp_index: i,
    _comp_skip: false
  }
}));

const items = $input.all();
const ctx = items[0].json;

// Если конкуренты были пропущены
if (ctx._comp_skip) {
  return [{ json: {
    ...ctx,
    competitor_matrix: [],
    competitor_cf_coverage: {},
    competitors_analyzed: 0,
    has_competitor_data: false,
    competitor_context: '(Конкуренты не указаны)\n'
  }}];
}

const matrix = [];
for (const item of items) {
  const url = item.json._comp_url || '';
  const html = String(item.json.data || item.json.body || '').toLowerCase();

  if (!html || html.length < 100) {
    matrix.push({ url, error: 'fetch_failed', cf_count: 0 });
    continue;
  }

  const cf = {
    url,
    has_price: /цен[аы]|price|₽|руб[\.\s]|стоимость|прайс|тариф|рассрочк/i.test(html),
    has_phone: /\+7|8[\s\-]?\(?\d{3}\)?|tel:|phone/i.test(html),
    has_email: /[\w.\-]+@[\w.\-]+\.[a-z]{2,}/i.test(html),
    has_address: /адрес|address|проезд|метро|ул\.|пр\.|улица|проспект/i.test(html),
    has_reviews: /отзыв|review|testimonial|рейтинг/i.test(html),
    has_license: /лицензи|сертификат|license|certificate|свидетельств/i.test(html),
    has_guarantee: /гарант|warranty|guarantee|возврат/i.test(html),
    has_portfolio: /портфолио|portfolio|наши работы|примеры|кейс|до и после|фото работ/i.test(html),
    has_faq: /faq|вопрос.*ответ|частые вопросы|частый вопрос/i.test(html),
    has_schema: /application\/ld\+json|itemtype|itemscope/i.test(html),
    has_callback: /callback|обратный звонок|заказать звонок|перезвон/i.test(html),
    has_chat: /whatsapp|telegram|viber|messenger|онлайн.?консультант|jivosite|carrot/i.test(html),
    has_map: /yandex.*map|google.*map|2gis|карта проезда|яндекс.*карт/i.test(html),
    has_team: /команд[аы]|специалист|врач[ие]|наши врачи|staff|team/i.test(html),
    has_legal: /полити[кч]а конфиденциальности|оферт|пользовательское соглашен|privacy/i.test(html),
    has_payment: /оплат|payment|visa|mastercard|мир\b|рассрочк|кредит|долями/i.test(html),
    has_schedule: /расписан|режим работы|график|часы работы|working hours|пн|вт|ср|чт|пт/i.test(html)
  };

  cf.cf_count = Object.entries(cf).filter(([k,v]) => k.startsWith('has_') && v === true).length;
  matrix.push(cf);
}

// Coverage: сколько конкурентов имеют каждый КФ
const cfTypes = Object.keys(matrix[0] || {}).filter(k => k.startsWith('has_'));
const coverage = {};
const validMatrix = matrix.filter(m => !m.error);

cfTypes.forEach(cf => {
  const withCf = validMatrix.filter(m => m[cf]).length;
  coverage[cf] = {
    competitors_with: withCf,
    total: validMatrix.length,
    ratio: validMatrix.length ? +(withCf / validMatrix.length).toFixed(2) : 0,
    label: cf.replace('has_', ''),
    critical: withCf / Math.max(validMatrix.length, 1) >= 0.6 // У 60%+ конкурентов → критично для нас
  };
});

// Build human-readable context for prompt
let compContext = '\n=== РЕАЛЬНЫЕ КФ КОНКУРЕНТОВ (парсинг HTML) ===\n\n';
validMatrix.forEach((c, i) => {
  const present = Object.entries(c)
    .filter(([k,v]) => k.startsWith('has_') && v === true)
    .map(([k]) => k.replace('has_', ''))
    .join(', ');
  compContext += `Конкурент ${i+1} (${c.url}): ${present} [${c.cf_count} КФ]\n`;
});

const criticalGaps = Object.values(coverage)
  .filter(c => c.critical)
  .map(c => c.label);

if (criticalGaps.length > 0) {
  compContext += `\n⚠ КФ ЕСТЬ У 60%+ КОНКУРЕНТОВ (критично внедрить): ${criticalGaps.join(', ')}\n`;
}

// Restore original context (first item has all data)
const baseCtx = items[0].json;

return [{ json: {
  niche: baseCtx.niche,
  city: baseCtx.city,
  project_id: baseCtx.project_id,
  target_url: baseCtx.target_url,
  competitors: baseCtx.competitors,
  has_competitors: baseCtx.has_competitors,
  niche_cluster: baseCtx.niche_cluster,
  embed_query: baseCtx.embed_query,
  started_at: baseCtx.started_at,
  workflow_version: baseCtx.workflow_version,
  source: baseCtx.source,
  rag_context: baseCtx.rag_context,
  rag_persona_count: baseCtx.rag_persona_count,
  rag_struct_count: baseCtx.rag_struct_count,
  pages: baseCtx.pages,
  pages_count: baseCtx.pages_count,
  pages_context: baseCtx.pages_context,
  eeat_score: baseCtx.eeat_score,
  eeat_available: baseCtx.eeat_available,
  competitor_matrix: matrix,
  competitor_cf_coverage: coverage,
  competitors_analyzed: validMatrix.length,
  competitors_failed: matrix.filter(m => m.error).length,
  has_competitor_data: validMatrix.length > 0,
  competitor_context: compContext,
  competitor_critical_gaps: criticalGaps
}}];

const ctx = $input.first().json;

// ── Niche cluster specific hints ──
const clusterHints = {
  commercial_local: `[Я] КФ, ПФ, Local SEO — главные приоритеты для локального бизнеса.
[Я] Яндекс.Бизнес, 2GIS, карты — обязательно. ИКС зависит от КФ напрямую.
[G] Google Business Profile, LocalBusiness schema, click-to-call.
[ОБА] Цены, контакты, отзывы, гарантии — топ-факторы.`,

  ecom: `[ОБА] Ассортимент — МУЛЬТИПЛИКАТОР в формуле КФ. Без него всё обнуляется.
[Я] Фильтры, Product schema, наличие на складе, варианты доставки.
[G] Product/Offer schema, MerchantReturnPolicy, ShippingDetails.
Каннибализация: проверить пересечение семантики между страницами.`,

  saas: `[G] GEO/AEO приоритет. AI Overviews — главная угроза.
[ОБА] Blog pipeline, Entity SEO, Wikidata.
Международное SEO, hreflang, мультиязычность.`,

  info: `[ОБА] E-E-A-T авторов — критично. YMYL-требования.
[ОБА] Content Decay мониторинг. Частота обновлений.
[G] HCU compliance — anti-AI-spam.`,

  commercial_national: `[ОБА] Ссылочный профиль + E-E-A-T — главные драйверы.
[G] Featured Snippets, SERP features — оптимизация обязательна.
[Я] ПФ: CTR + dwell time + bounce — 45% формулы ранжирования.`
};

const clusterCtx = clusterHints[ctx.niche_cluster] || clusterHints.commercial_local;

// ── EEAT context ──
let eeatBlock = '';
if (ctx.eeat_available && ctx.eeat_score) {
  const e = ctx.eeat_score;
  eeatBlock = `\n## ТЕКУЩИЙ E-E-A-T SCORE (из аудита workflow #06)
Experience: ${e.experience_score || 'N/A'}/10 | Expertise: ${e.expertise_score || 'N/A'}/10
Authority: ${e.authority_score || 'N/A'}/10 | Trust: ${e.trust_score || 'N/A'}/10
→ Учитывай при приоритизации: если Trust низкий — КФ доверия в priority 1.\n`;
}

// ── Competitor data ──
const compContext = ctx.has_competitor_data
  ? ctx.competitor_context
  : '(Данные конкурентов недоступны — рекомендации на основе лучших практик ниши)\n';

const systemPrompt = `Ты Senior SEO-аудитор с 10+ лет опыта в коммерческом SEO (Яндекс и Google). Год: 2026.
Формат ответа: ТОЛЬКО валидный JSON. Ни одного символа вне JSON.

РОЛЬ: Провести экспертный аудит коммерческих факторов ранжирования.
ПРОЕКТ: Ниша "${ctx.niche}" | Город: "${ctx.city}" | Кластер: ${ctx.niche_cluster}

${ctx.rag_context}
${ctx.pages_context}
${compContext}
${eeatBlock}

## [Я] ФОРМУЛА КОММЕРЧЕСКОЙ РЕЛЕВАНТНОСТИ ЯНДЕКСА (2026)
КР = Ассортимент × (2×Надёжность + Удобство + Дизайн + 2×Сервис)
ВАЖНО:
- Ассортимент — МУЛЬТИПЛИКАТОР. Без ассортимента/цен всё обнуляется.
- Надёжность (лицензии, реквизиты, отзывы) и Сервис (контакты, доставка, гарантии) имеют ДВОЙНОЙ вес.
- ПФ весят 45% в формуле ранжирования Яндекса (2026).

## [G] GOOGLE — E-E-A-T + CWV + HCU (2026)
- E-E-A-T: реальный опыт автора, экспертиза, авторитетность, доверие
- Structured Data: LocalBusiness, Service, FAQPage, PriceSpecification, Speakable
- AI Overviews / SGE: GEO-оптимизация обязательна — cite-friendly факты

## СПЕЦИФИКА КЛАСТЕРА: ${ctx.niche_cluster}
${clusterCtx}

## КЛАССИФИКАЦИЯ КОММЕРЧЕСКИХ ФАКТОРОВ
### Яндекс-специфичные:
- price: Прайс-лист, таблица цен, калькулятор, рассрочка/кредит
- contact: Телефон, адрес, email, мессенджеры, карта, режим работы, callback
- trust: Сертификаты, лицензии, ИНН/ОГРН, членства, партнёры, награды
- review: Отзывы клиентов, рейтинги, кейсы до/после, видеоотзывы
- guarantee: Гарантии, возврат, сервис, страхование
- portfolio: Портфолио, фото работ, кейсы, примеры
- conversion: Формы, онлайн-запись, callback, CTA-блоки, квиз
- legal: Политика конфиденциальности, оферта, реквизиты
- delivery: Доставка, самовывоз, логистика (если применимо)
- team: Команда, специалисты, опыт, фото, регалии

### Google-специфичные:
- schema: Structured Data (LocalBusiness, Service, FAQPage, PriceSpecification, Speakable)
- content: Breadcrumbs, FAQ, HowTo, экспертный контент

### AEO/GEO (2026):
- aeo: FAQ с прямыми ответами, Speakable, цитируемая статистика, entity-факты

## ПРИМЕР (ниша: стоматология, Москва, commercial_local):
