## ПРАВИЛА
1. Анализируй КОНКРЕТНО для ниши "${ctx.niche}" — не абстрактно
2. Каждая рекомендация — actionable (что именно сделать)
3. priority: 1=критично, 2=важно, 3=желательно, 4=опционально, 5=перспектива
4. Не дублируй факторы — каждый уникален
5. search_engine: "yandex" | "google" | "both" — НЕ СТАВЬ "both" по умолчанию
6. [Я]-специфичные: priority 1-2 для КФ с двойным весом (Надёжность, Сервис)
7. Если есть данные конкурентов — отмечай competitor_gap: true/false
8. yandex_formula_component: "assortment" | "trust" | "service" | "usability" | "design" | "n/a"

## JSON SCHEMA (строго следуй):
{
  "commercial_factors": [
    {
      "factor_name": "string",
      "factor_type": "price|contact|trust|review|guarantee|portfolio|conversion|legal|delivery|team|schema|content|aeo",
      "description": "string — конкретная рекомендация для ниши ${ctx.niche}",
      "priority": "number 1-5",
      "search_engine": "yandex|google|both",
      "implementation_hint": "string",
      "expected_impact": "high|medium|low",
      "yandex_formula_component": "assortment|trust|service|usability|design|n/a",
      "competitor_gap": "boolean"
    }
  ],
  "summary": {
    "total_factors": "number",
    "critical_count": "number",
    "yandex_critical": "number",
    "google_critical": "number",
    "top3_quick_wins": ["string"],
    "cf_formula_assessment": {
      "assortment": "missing|partial|complete",
      "trust": "missing|partial|complete",
      "service": "missing|partial|complete",
      "usability": "missing|partial|complete",
      "design": "missing|partial|complete"
    }
  }
}`;

const userPrompt = `Проведи аудит коммерческих факторов для проекта.
Ниша: ${ctx.niche}
Город: ${ctx.city}
Кластер: ${ctx.niche_cluster}
Страниц: ${ctx.pages_count}
Конкурентов проанализировано: ${ctx.competitors_analyzed || 0}
E-E-A-T данные: ${ctx.eeat_available ? 'доступны' : 'нет'}

Выдай от 18 до 35 факторов, отсортированных по priority (от 1 к 5).
ОБЯЗАТЕЛЬНО: минимум 3 фактора с search_engine="yandex", минимум 3 с "google", минимум 2 с "aeo".
Если есть данные конкурентов — обязательно отметь competitor_gap.
Ответ — ТОЛЬКО JSON.`;

const payload = {
  model: 'llama-3.3-70b-versatile',
  max_tokens: 8192,
  temperature: 0.15,
  top_p: 0.85,
  response_format: { type: "json_object" },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};

return [{ json: {
  groq_payload: payload,
  batch_info: {
    project_id: ctx.project_id,
    niche: ctx.niche,
    city: ctx.city,
    target_url: ctx.target_url,
    niche_cluster: ctx.niche_cluster,
    competitors_analyzed: ctx.competitors_analyzed || 0,
    eeat_available: ctx.eeat_available,
    source: ctx.source,
    started_at: ctx.started_at
  },
  competitor_data: {
    matrix: ctx.competitor_matrix || [],
    coverage: ctx.competitor_cf_coverage || {},
    critical_gaps: ctx.competitor_critical_gaps || []
  },
  pages_count: ctx.pages_count,
  rag_stats: {
    personas: ctx.rag_persona_count,
    structures: ctx.rag_struct_count,
    quality_filtered: ctx.rag_quality_filtered || 0
  }
}}];

const groqResponse = $input.first().json;
const batchInfo = $('Build CF Prompt v4.0').first().json.batch_info;

if (groqResponse.error) {
  const errMsg = groqResponse.error.message || JSON.stringify(groqResponse.error);
  return [{ json: {
    success: false,
    factors_count: 0,
    factors: [],
    nocodb_payload: [],
    error: 'Groq API error: ' + errMsg,
    groq_tokens: 0,
    batch_info: batchInfo
  }}];
}

const rawContent = groqResponse?.choices?.[0]?.message?.content || '';
const tokens = groqResponse?.usage?.total_tokens || 0;
const finishReason = groqResponse?.choices?.[0]?.finish_reason || 'unknown';

// Parse JSON
let parsed;
try {
  parsed = JSON.parse(rawContent);
} catch (err) {
  const cleaned = rawContent.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
  try {
    parsed = JSON.parse(cleaned);
  } catch(e2) {
    return [{ json: {
      success: false,
      factors_count: 0,
      factors: [],
      nocodb_payload: [],
      error: 'JSON parse failed: ' + err.message + '. Raw[0:500]: ' + rawContent.substring(0, 500),
      groq_tokens: tokens,
      batch_info: batchInfo
    }}];
  }
}

// Normalize
if (Array.isArray(parsed)) parsed = { commercial_factors: parsed, summary: null };
if (!parsed.commercial_factors && parsed.factor_name) parsed = { commercial_factors: [parsed], summary: null };

const validTypes = ['price','contact','trust','review','legal','conversion','content','aeo','guarantee','portfolio','delivery','team','schema'];
const validEngines = ['yandex','google','both'];
const validImpact = ['high','medium','low'];
const validFormula = ['assortment','trust','service','usability','design','n/a'];

const factors = (parsed.commercial_factors || []).map((f, idx) => ({
  project_id: batchInfo.project_id,
  niche: batchInfo.niche,
  city: batchInfo.city,
  niche_cluster: batchInfo.niche_cluster,
  factor_name: (f.factor_name || 'Фактор ' + (idx+1)).substring(0, 200),
  factor_type: validTypes.includes(f.factor_type) ? f.factor_type : 'content',
  description: (f.description || '').substring(0, 2000),
  priority: Math.min(Math.max(parseInt(f.priority) || 3, 1), 5),
  search_engine: validEngines.includes(f.search_engine) ? f.search_engine : 'both',
  implementation_hint: (f.implementation_hint || '').substring(0, 500),
  expected_impact: validImpact.includes(f.expected_impact) ? f.expected_impact : 'medium',
  yandex_formula_component: validFormula.includes(f.yandex_formula_component) ? f.yandex_formula_component : 'n/a',
  competitor_gap: !!f.competitor_gap,
  status: 'pending',
  created: new Date().toISOString(),
  workflow_version: 'v4.0'
}));

// Validate minimum requirements
const warnings = [];
const yaFactors = factors.filter(f => f.search_engine === 'yandex').length;
const gFactors = factors.filter(f => f.search_engine === 'google').length;
const aeoFactors = factors.filter(f => f.factor_type === 'aeo').length;
if (yaFactors < 3) warnings.push('[Я] факторов < 3 (получено: ' + yaFactors + ')');
if (gFactors < 3) warnings.push('[G] факторов < 3 (получено: ' + gFactors + ')');
if (aeoFactors < 2) warnings.push('AEO факторов < 2 (получено: ' + aeoFactors + ')');

const summary = parsed.summary || {
  total_factors: factors.length,
  critical_count: factors.filter(f => f.priority === 1).length,
  yandex_critical: factors.filter(f => f.search_engine === 'yandex' && f.priority === 1).length,
  google_critical: factors.filter(f => f.search_engine === 'google' && f.priority === 1).length,
  top3_quick_wins: factors.filter(f => f.expected_impact === 'high').slice(0, 3).map(f => f.factor_name),
  cf_formula_assessment: null
};

return [{ json: {
  success: true,
  factors_count: factors.length,
  factors: factors,
  nocodb_payload: factors,
  summary: summary,
  groq_tokens: tokens,
  finish_reason: finishReason,
  warnings: warnings,
  error: null,
  batch_info: batchInfo
}}];

const prev = $input.first().json;
const batchInfo = prev.batch_info || {};
const startedAt = batchInfo.started_at;
const elapsed = startedAt ? ((new Date() - new Date(startedAt)) / 1000).toFixed(1) : 0;

return [{ json: {
  success: false,
  workflow_version: 'v4.0_ultra',
  execution_time_sec: parseFloat(elapsed),
  error: prev.error || 'LLM failed: no factors returned',
  factors_count: 0,
  groq_tokens: prev.groq_tokens || 0,
  metadata: {
    niche: batchInfo.niche,
    city: batchInfo.city,
    project_id: batchInfo.project_id,
    source: batchInfo.source
  },
  timestamp: new Date().toISOString()
}}];

const cfInfo = $('Parse CF Response').first().json;
const compData = $('Build Competitor CF Matrix').first().json;
const factors = cfInfo.factors || [];
const batchInfo = cfInfo.batch_info || {};

const validTypes = ['price','contact','trust','review','legal','conversion','content','aeo','guarantee','portfolio','delivery','team','schema'];

// ── Группировка по типам ──
const typeGroups = {};
validTypes.forEach(t => { typeGroups[t] = []; });
factors.forEach(f => {
  if (typeGroups[f.factor_type]) typeGroups[f.factor_type].push(f);
});

// ── Количественные фичи (не бинарные!) ──
const features = {};

// Per-type count + avg priority
validTypes.forEach(t => {
  const group = typeGroups[t];
  features[t + '_count'] = group.length;
  features[t + '_avg_priority'] = group.length
    ? +(group.reduce((s, f) => s + f.priority, 0) / group.length).toFixed(2)
    : 0;
  features[t + '_high_impact'] = group.filter(f => f.expected_impact === 'high').length;
});

// Aggregates
features.total_factors = factors.length;
features.critical_count = factors.filter(f => f.priority === 1).length;
features.high_impact_count = factors.filter(f => f.expected_impact === 'high').length;
features.type_diversity = new Set(factors.map(f => f.factor_type)).size;
features.avg_priority = factors.length
  ? +(factors.reduce((s, f) => s + f.priority, 0) / factors.length).toFixed(2)
  : 0;

// Engine split [Я]/[G]
features.yandex_only = factors.filter(f => f.search_engine === 'yandex').length;
features.google_only = factors.filter(f => f.search_engine === 'google').length;
features.both_engines = factors.filter(f => f.search_engine === 'both').length;
features.yandex_critical = factors.filter(f =>
  (f.search_engine === 'yandex' || f.search_engine === 'both') && f.priority === 1
).length;
features.google_critical = factors.filter(f =>
  (f.search_engine === 'google' || f.search_engine === 'both') && f.priority === 1
).length;

// КФ формула Яндекса (приблизительная оценка)
const formulaAssort = typeGroups.price.length > 0 ? 1 : 0;
const formulaTrust = (typeGroups.trust.length + typeGroups.legal.length + typeGroups.review.length) * 2;
const formulaService = (typeGroups.contact.length + typeGroups.guarantee.length + typeGroups.delivery.length) * 2;
const formulaUsability = typeGroups.conversion.length;
const formulaDesign = typeGroups.portfolio.length;
features.cf_formula_score = formulaAssort * (formulaTrust + formulaUsability + formulaDesign + formulaService);

// Competitor gap
features.competitor_gap_count = factors.filter(f => f.competitor_gap).length;
features.competitor_gap_critical = factors.filter(f => f.competitor_gap && f.priority === 1).length;
if (compData && compData.has_competitor_data) {
  const gaps = compData.competitor_critical_gaps || [];
  features.competitor_critical_gap_count = gaps.length;
  features.competitors_analyzed = compData.competitors_analyzed;
} else {
  features.competitor_critical_gap_count = -1;
  features.competitors_analyzed = 0;
}

// ── Embedding text — ВСЕ факторы, не только top 10 ──
const embedText = [
  'Коммерческие факторы SEO аудит',
  'Ниша: ' + batchInfo.niche,
  'Город: ' + batchInfo.city,
  'Кластер: ' + (batchInfo.niche_cluster || ''),
  'Всего факторов: ' + factors.length,
  'Критичных: ' + features.critical_count,
  'Яндекс: ' + features.yandex_only + ' | Google: ' + features.google_only + ' | Оба: ' + features.both_engines,
  'Формула КФ score: ' + features.cf_formula_score,
  '',
  'Факторы по приоритету:',
  ...factors
    .sort((a, b) => a.priority - b.priority)
    .map(f => `P${f.priority} [${f.search_engine}] ${f.factor_name} (${f.factor_type}) — ${f.expected_impact}`)
].join('\n');

return [{ json: {
  ml_features: features,
  embed_text: embedText,
  cf_info: cfInfo,
  batch_info: batchInfo,
  competitor_data: compData
}}];

const mlPrep = $('Prepare ML Features v2').first().json;

// NocoDB status
let nocodbOk = false;
try {
  const nocoResult = $('NocoDB Upsert').first().json;
  nocodbOk = Array.isArray(nocoResult) ? nocoResult.length > 0 : !!nocoResult?.Id;
} catch(e) {}

// ML result
let mlScore = null, mlLabel = null, mlConfidence = null;
try {
  const ml = $('ML CF Impact').first().json;
  mlScore = ml.score ?? null;
  mlLabel = ml.label ?? null;
  mlConfidence = ml.confidence ?? null;
} catch(e) {}

// Embedding
let embedding = null;
try {
  embedding = $('Embed Full Summary').first().json.embedding;
} catch(e) {}

return [{ json: {
  ...mlPrep,
  ml_cf_score: mlScore,
  ml_cf_label: mlLabel,
  ml_confidence: mlConfidence,
  embedding: embedding,
  nocodb_saved: nocodbOk,
  nocodb_result: nocodbOk ? 'OK' : 'FAIL'
}}];

const prev = $input.first().json;
const vector = prev.embedding;

if (!vector || !Array.isArray(vector) || vector.length !== 1024) {
  return [{ json: { ...prev, qdrant_saved: false, qdrant_skip_reason: 'Invalid embedding (len=' + (vector?.length || 0) + ')' }}];
}

// Deterministic UUID: same project + date = same point (upsert, not duplicate)
const dateKey = new Date().toISOString().substring(0, 10); // YYYY-MM-DD
const raw = prev.batch_info.project_id + '_cf_' + dateKey;
// Simple hash → UUID v5 style
let hash = 0;
for (let i = 0; i < raw.length; i++) {
  hash = ((hash << 5) - hash) + raw.charCodeAt(i);
  hash |= 0;
}
const hex = Math.abs(hash).toString(16).padStart(8, '0');
const pointId = hex.substring(0,8) + '-' + hex.substring(0,4) + '-4' + hex.substring(1,4) + '-8' + hex.substring(2,5) + '-' + hex.substring(0,12).padEnd(12,'0');

const payload = {
  points: [{
    id: pointId,
    vector: vector,
    payload: {
      project_id: prev.batch_info.project_id,
      niche: prev.batch_info.niche,
      niche_cluster: prev.batch_info.niche_cluster || '',
      city: prev.batch_info.city,
      type: 'commercial_factors_analysis',
      factors_count: prev.cf_info.factors_count,
      critical_count: prev.ml_features.critical_count,
      ml_score: prev.ml_cf_score,
      ml_label: prev.ml_cf_label,
      cf_formula_score: prev.ml_features.cf_formula_score,
      yandex_critical: prev.ml_features.yandex_critical,
      google_critical: prev.ml_features.google_critical,
      competitor_gap_count: prev.ml_features.competitor_gap_count,
      competitors_analyzed: prev.ml_features.competitors_analyzed,
      summary: JSON.stringify(prev.cf_info.summary || {}),
      top_factors: prev.cf_info.factors?.slice(0, 8).map(f => f.factor_name).join(', ') || '',
      warnings: (prev.cf_info.warnings || []).join('; '),
      created: new Date().toISOString(),
      workflow_version: 'v4.0'
    }
  }]
};

return [{ json: { ...prev, qdrant_payload: payload, qdrant_point_id: pointId }}];

const prev = $input.first().json;
const cfInfo = prev.cf_info;
const startedAt = prev.batch_info.started_at;

let qdrantOk = false;
try {
  const qRes = $('Save to Qdrant').first().json;
  qdrantOk = qRes.result?.status === 'acknowledged' || qRes.status === 'ok' || !!prev.qdrant_point_id;
} catch(e) {}

const elapsed = startedAt ? ((new Date() - new Date(startedAt)) / 1000).toFixed(1) : 0;

// Engine split stats
const factors = cfInfo.factors || [];
const yandexFactors = factors.filter(f => f.search_engine === 'yandex');
const googleFactors = factors.filter(f => f.search_engine === 'google');
const bothFactors = factors.filter(f => f.search_engine === 'both');
const aeoFactors = factors.filter(f => f.factor_type === 'aeo');

return [{ json: {
  success: true,
  workflow_version: 'v4.0_ultra',
  execution_time_sec: parseFloat(elapsed),

  // Core results
  factors_count: cfInfo.factors_count,
  factors: factors,
  summary: cfInfo.summary || {},

  // Engine split [Я]/[G]/[ОБА]
  engine_split: {
    yandex: { count: yandexFactors.length, critical: yandexFactors.filter(f => f.priority === 1).length },
    google: { count: googleFactors.length, critical: googleFactors.filter(f => f.priority === 1).length },
    both: { count: bothFactors.length, critical: bothFactors.filter(f => f.priority === 1).length },
    aeo: { count: aeoFactors.length }
  },

  // КФ формула Яндекса
  cf_formula: {
    score: prev.ml_features.cf_formula_score,
    components: cfInfo.summary?.cf_formula_assessment || null
  },

  // Competitor gap
  competitor_analysis: {
    analyzed: prev.batch_info.competitors_analyzed,
    gap_factors: prev.ml_features.competitor_gap_count,
    critical_gaps: prev.competitor_data?.critical_gaps || []
  },

  // ML enrichment
  ml_impact: {
    score: prev.ml_cf_score,
    label: prev.ml_cf_label,
    confidence: prev.ml_confidence,
    available: prev.ml_cf_score !== null
  },

  // Storage status
  storage: {
    nocodb: prev.nocodb_saved ? 'saved' : 'failed',
    qdrant: qdrantOk ? 'saved' : 'skipped',
    qdrant_collection: 'cf_analysis_results',
    qdrant_point_id: prev.qdrant_point_id || null
  },

  // Metadata
  metadata: {
    niche: prev.batch_info.niche,
    city: prev.batch_info.city,
    project_id: prev.batch_info.project_id,
    niche_cluster: prev.batch_info.niche_cluster,
    source: prev.batch_info.source,
    groq_tokens: cfInfo.groq_tokens || 0,
    rag_sources: prev.rag_stats || {},
    eeat_available: prev.batch_info.eeat_available
  },

  // Warnings
  warnings: cfInfo.warnings || [],
  errors: [
    ...(!prev.nocodb_saved ? ['NocoDB save failed'] : []),
    ...(!qdrantOk ? ['Qdrant save skipped'] : [])
  ].filter(Boolean)
}}];
